import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Credits and Settlement","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/contracts/credits-and-settlement.md","filePath":"projects/arti/contracts/credits-and-settlement.md"}'),l={name:"projects/arti/contracts/credits-and-settlement.md"};function o(d,e,n,s,c,p){return a(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="credits-and-settlement" tabindex="-1">Credits and Settlement <a class="header-anchor" href="#credits-and-settlement" aria-label="Permalink to &quot;Credits and Settlement&quot;">​</a></h1><p><strong>状态：Current</strong></p><p><strong>核对日期：2026-06-15</strong></p><p><strong>Shared DB Owner：<code>arti</code></strong></p><h2 id="核心不变量" tabindex="-1">核心不变量 <a class="header-anchor" href="#核心不变量" aria-label="Permalink to &quot;核心不变量&quot;">​</a></h2><ol><li>扣费发生在产出结果的服务端入口。</li><li>前端只展示余额和预览，不直接调用消费 RPC。</li><li>价格来自 <code>credit_pricing</code>，业务代码传 Action，不硬编码金额。</li><li>缓存命中免费。</li><li>扣费后未产出结果必须退款。</li><li>下注和消费按经济性质使用不同余额语义。</li></ol><h2 id="服务端入口" tabindex="-1">服务端入口 <a class="header-anchor" href="#服务端入口" aria-label="Permalink to &quot;服务端入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>权威入口</th></tr></thead><tbody><tr><td>报告</td><td><code>ARTI_backend</code> 报告创建服务</td></tr><tr><td>快速扫描</td><td>对应 Edge Function 或 Railway 服务</td></tr><tr><td>Chat 按量计费</td><td>Chat 服务端</td></tr><tr><td>预测 AI 分析</td><td><code>ARTi-poly</code> 服务端</td></tr><tr><td>下注与卖出</td><td><code>ARTi-poly</code> gateway + Shared DB RPC；仍有客户端经济学参数</td></tr><tr><td>市场结算</td><td>Shared DB RPC / settlement job</td></tr></tbody></table><h2 id="钱包语义" tabindex="-1">钱包语义 <a class="header-anchor" href="#钱包语义" aria-label="Permalink to &quot;钱包语义&quot;">​</a></h2><ul><li><code>balance</code>：AI 消费与通用 Credits。</li><li><code>predict_balance</code>：预测市场可用余额。</li><li>周额度是窗口计算结果，不应被误建模为永久余额。</li><li><code>frozen_balance</code> 不得为负。</li></ul><p>具体列名和资金优先级以当前 migration 为准。</p><h2 id="发布顺序" tabindex="-1">发布顺序 <a class="header-anchor" href="#发布顺序" aria-label="Permalink to &quot;发布顺序&quot;">​</a></h2><p>涉及新计费 Action 时：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>定价行</span></span>
<span class="line"><span>  → DB RPC / permission</span></span>
<span class="line"><span>  → 服务端调用方</span></span>
<span class="line"><span>  → 前端展示</span></span></code></pre></div><p>定价未先上线时，调用方可能返回 <code>pricing_not_found</code>。不得把前端 fallback 成免费执行。</p><h2 id="共享-rpc-修改" tabindex="-1">共享 RPC 修改 <a class="header-anchor" href="#共享-rpc-修改" aria-label="Permalink to &quot;共享 RPC 修改&quot;">​</a></h2><p>修改 <code>place_bet</code>、<code>sell_position</code>、<code>settle_market</code> 等函数前：</p><ul><li>查询生产当前函数定义</li><li>检查 <code>arti</code> 与 <code>ARTi-poly</code> 是否存在更新版本</li><li>只由当前 Owner 新增 migration</li><li>运行正常流程和对抗性直连测试</li><li>验证通知、流水和余额同时正确</li></ul><h2 id="已知完整性缺口" tabindex="-1">已知完整性缺口 <a class="header-anchor" href="#已知完整性缺口" aria-label="Permalink to &quot;已知完整性缺口&quot;">​</a></h2><p>截至 2026-06-15，最新 <code>place_bet</code> 和 <code>sell_position</code> migration 仍接受客户端传入的：</p><ul><li><code>shares</code></li><li><code>proceeds</code></li><li>新池子值</li><li>平均价格等经济学参数</li></ul><p>现有服务端校验不能等同于“服务端重新计算”。<code>ARTi-poly</code> RFC-2026-0017 提出的服务端 LMSR 重算仍是 Proposed，不应被描述为已实施。</p><p>目标状态：</p><ul><li>客户端只提交意图和金额</li><li>服务端锁定市场与仓位</li><li>服务端重新计算 Shares、Proceeds 和池子</li><li>客户端计算只用于预览</li><li>使用对抗性测试证明无法伪造成交结果</li></ul><h2 id="禁止" tabindex="-1">禁止 <a class="header-anchor" href="#禁止" aria-label="Permalink to &quot;禁止&quot;">​</a></h2><ul><li>前端直接消费 Credits</li><li>新代码继续扩大对客户端成交份额、收益或池子值的信任</li><li>把预测市场预览算法当作服务端安全边界</li><li>从另一个仓库复制旧函数后整体 <code>CREATE OR REPLACE</code></li><li>在缓存检查前扣费</li></ul><h2 id="实现真源" tabindex="-1">实现真源 <a class="header-anchor" href="#实现真源" aria-label="Permalink to &quot;实现真源&quot;">​</a></h2><ul><li><a href="https://github.com/iloveopt/arti/blob/main/docs/rfcs/0010-server-authoritative-credits.md" target="_blank" rel="noreferrer">Server-authoritative Credits RFC</a></li><li><a href="https://github.com/iloveopt/arti/tree/main/supabase/migrations" target="_blank" rel="noreferrer"><code>arti</code> migrations</a></li><li><a href="https://github.com/botearn/ARTi-poly/blob/main/rfcs/2026/RFC-2026-0017-server-authoritative-credits.md" target="_blank" rel="noreferrer">Prediction trading authority proposal</a></li><li><a href="https://github.com/botearn/ARTi-poly/tree/main/rfcs" target="_blank" rel="noreferrer">Prediction market RFC index</a></li></ul>`,28)])])}const b=t(l,[["render",o]]);export{u as __pageData,b as default};
